// app1 (远程应用)
new ModuleFederationPlugin({
  name: 'app1',
  filename: 'remoteEntry.js',
  exposes: { './Button': './src/Button' },
  shared: { react: { singleton: true } }
});

// host (宿主应用)
new ModuleFederationPlugin({
  name: 'host',
  remotes: { app1: 'app1@http://localhost:3001/remoteEntry.js' },
  shared: { react: { singleton: true } }
});
// React.lazy(() => import('app1/Button')) 加载远程组件
